// CloudBuildServer is the server API for CloudBuild service.
// All implementations should embed UnimplementedCloudBuildServer
// for forward compatibility
type CloudBuildServer interface {
	// Starts a build with the specified configuration.
	//
	// This method returns a long-running `Operation`, which includes the build
	// ID. Pass the build ID to `GetBuild` to determine the build status (such as
	// `SUCCESS` or `FAILURE`).
	CreateBuild(context.Context, *CreateBuildRequest) (*longrunningpb.Operation, error)
	// Returns information about a previously requested build.
	//
	// The `Build` that is returned includes its status (such as `SUCCESS`,
	// `FAILURE`, or `WORKING`), and timing information.
	GetBuild(context.Context, *GetBuildRequest) (*Build, error)
	// Lists previously requested builds.
	//
	// Previously requested builds may still be in-progress, or may have finished
	// successfully or unsuccessfully.
	ListBuilds(context.Context, *ListBuildsRequest) (*ListBuildsResponse, error)
	// Cancels a build in progress.
	CancelBuild(context.Context, *CancelBuildRequest) (*Build, error)
	// Creates a new build based on the specified build.
	//
	// This method creates a new build using the original build request, which may
	// or may not result in an identical build.
	//
	// For triggered builds:
	//
	// * Triggered builds resolve to a precise revision; therefore a retry of a
	// triggered build will result in a build that uses the same revision.
	//
	// For non-triggered builds that specify `RepoSource`:
	//
	// * If the original build built from the tip of a branch, the retried build
	// will build from the tip of that branch, which may not be the same revision
	// as the original build.
	// * If the original build specified a commit sha or revision ID, the retried
	// build will use the identical source.
	//
	// For builds that specify `StorageSource`:
	//
	// * If the original build pulled source from Cloud Storage without
	// specifying the generation of the object, the new build will use the current
	// object, which may be different from the original build source.
	// * If the original build pulled source from Cloud Storage and specified the
	// generation of the object, the new build will attempt to use the same
	// object, which may or may not be available depending on the bucket's
	// lifecycle management settings.
	RetryBuild(context.Context, *RetryBuildRequest) (*longrunningpb.Operation, error)
	// Approves or rejects a pending build.
	//
	// If approved, the returned long-running operation (LRO) will be analogous to
	// the LRO returned from a CreateBuild call.
	//
	// If rejected, the returned LRO will be immediately done.
	ApproveBuild(context.Context, *ApproveBuildRequest) (*longrunningpb.Operation, error)
	// Creates a new `BuildTrigger`.
	CreateBuildTrigger(context.Context, *CreateBuildTriggerRequest) (*BuildTrigger, error)
	// Returns information about a `BuildTrigger`.
	GetBuildTrigger(context.Context, *GetBuildTriggerRequest) (*BuildTrigger, error)
	// Lists existing `BuildTrigger`s.
	ListBuildTriggers(context.Context, *ListBuildTriggersRequest) (*ListBuildTriggersResponse, error)
	// Deletes a `BuildTrigger` by its project ID and trigger ID.
	DeleteBuildTrigger(context.Context, *DeleteBuildTriggerRequest) (*emptypb.Empty, error)
	// Updates a `BuildTrigger` by its project ID and trigger ID.
	UpdateBuildTrigger(context.Context, *UpdateBuildTriggerRequest) (*BuildTrigger, error)
	// Runs a `BuildTrigger` at a particular source revision.
	//
	// To run a regional or global trigger, use the POST request
	// that includes the location endpoint in the path (ex.
	// v1/projects/{projectId}/locations/{region}/triggers/{triggerId}:run). The
	// POST request that does not include the location endpoint in the path can
	// only be used when running global triggers.
	RunBuildTrigger(context.Context, *RunBuildTriggerRequest) (*longrunningpb.Operation, error)
	// ReceiveGitHubDotComWebhook is called when the API receives a github.com
	// webhook.
	ReceiveGitHubDotComWebhook(context.Context, *WebhookRequest) (*emptypb.Empty, error)
	// ReceiveWebhook is called when the API receives a GitHub webhook.
	ReceiveWebhook(context.Context, *WebhookRequest) (*emptypb.Empty, error)
	// ReceiveTriggerWebhook [Experimental] is called when the API receives a
	// webhook request targeted at a specific trigger.
	ReceiveTriggerWebhook(context.Context, *ReceiveTriggerWebhookRequest) (*ReceiveTriggerWebhookResponse, error)
	// Creates a new `BitbucketServerConfig`.
	//
	// This API is experimental.
	CreateBitbucketServerConfig(context.Context, *CreateBitbucketServerConfigRequest) (*longrunningpb.Operation, error)
	// Updates an existing `BitbucketServerConfig`.
	//
	// This API is experimental.
	UpdateBitbucketServerConfig(context.Context, *UpdateBitbucketServerConfigRequest) (*longrunningpb.Operation, error)
	// Retrieve a `BitbucketServerConfig`.
	//
	// This API is experimental.
	GetBitbucketServerConfig(context.Context, *GetBitbucketServerConfigRequest) (*BitbucketServerConfig, error)
	// List all `BitbucketServerConfigs` for a given project.
	//
	// This API is experimental.
	ListBitbucketServerConfigs(context.Context, *ListBitbucketServerConfigsRequest) (*ListBitbucketServerConfigsResponse, error)
	// Delete a `BitbucketServerConfig`.
	//
	// This API is experimental.
	DeleteBitbucketServerConfig(context.Context, *DeleteBitbucketServerConfigRequest) (*longrunningpb.Operation, error)
	// List all repositories for a given `BitbucketServerConfig`.
	//
	// This API is experimental.
	ListBitbucketServerRepositories(context.Context, *ListBitbucketServerRepositoriesRequest) (*ListBitbucketServerRepositoriesResponse, error)
	// Remove a Bitbucket Server repository from a given
	// BitbucketServerConfig's connected repositories.
	//
	// This API is experimental.
	RemoveBitbucketServerConnectedRepository(context.Context, *RemoveBitbucketServerConnectedRepositoryRequest) (*emptypb.Empty, error)
	// Batch connecting Bitbucket Server repositories to Cloud Build.
	BatchCreateBitbucketServerConnectedRepositories(context.Context, *BatchCreateBitbucketServerConnectedRepositoriesRequest) (*longrunningpb.Operation, error)
	// Creates a new `GitLabConfig`.
	//
	// This API is experimental
	CreateGitLabConfig(context.Context, *CreateGitLabConfigRequest) (*longrunningpb.Operation, error)
	// Updates an existing `GitLabConfig`.
	//
	// This API is experimental
	UpdateGitLabConfig(context.Context, *UpdateGitLabConfigRequest) (*longrunningpb.Operation, error)
	// Retrieves a `GitLabConfig`.
	//
	// This API is experimental
	GetGitLabConfig(context.Context, *GetGitLabConfigRequest) (*GitLabConfig, error)
	// List all `GitLabConfigs` for a given project.
	//
	// This API is experimental
	ListGitLabConfigs(context.Context, *ListGitLabConfigsRequest) (*ListGitLabConfigsResponse, error)
	// Delete a `GitLabConfig`.
	//
	// This API is experimental
	DeleteGitLabConfig(context.Context, *DeleteGitLabConfigRequest) (*longrunningpb.Operation, error)
	// List all repositories for a given `GitLabConfig`.
	//
	// This API is experimental
	ListGitLabRepositories(context.Context, *ListGitLabRepositoriesRequest) (*ListGitLabRepositoriesResponse, error)
	// Remove a GitLab repository from a given GitLabConfig's connected
	// repositories.
	//
	// This API is experimental.
	RemoveGitLabConnectedRepository(context.Context, *RemoveGitLabConnectedRepositoryRequest) (*emptypb.Empty, error)
	// Batch connecting GitLab repositories to Cloud Build.
	//
	// This API is experimental.
	BatchCreateGitLabConnectedRepositories(context.Context, *BatchCreateGitLabConnectedRepositoriesRequest) (*longrunningpb.Operation, error)
	// Create an association between a GCP project and a GitHub Enterprise server.
	CreateGitHubEnterpriseConfig(context.Context, *CreateGitHubEnterpriseConfigRequest) (*longrunningpb.Operation, error)
	// Update an association between a GCP project and a GitHub Enterprise server.
	UpdateGitHubEnterpriseConfig(context.Context, *UpdateGitHubEnterpriseConfigRequest) (*longrunningpb.Operation, error)
	// Retrieve a GitHubEnterpriseConfig.
	GetGitHubEnterpriseConfig(context.Context, *GetGitHubEnterpriseConfigRequest) (*GitHubEnterpriseConfig, error)
	// List all GitHubEnterpriseConfigs for a given project.
	ListGitHubEnterpriseConfigs(context.Context, *ListGithubEnterpriseConfigsRequest) (*ListGithubEnterpriseConfigsResponse, error)
	// Delete an association between a GCP project and a GitHub Enterprise server.
	DeleteGitHubEnterpriseConfig(context.Context, *DeleteGitHubEnterpriseConfigRequest) (*longrunningpb.Operation, error)
	// ListBranches returns the list of git branches for the given repo.
	ListBranches(context.Context, *ListBranchesRequest) (*ListBranchesResponse, error)
	// ListTags returns the list of git tags for the given repo.
	ListTags(context.Context, *ListTagsRequest) (*ListTagsResponse, error)
	// Creates a `WorkerPool`.
	CreateWorkerPool(context.Context, *CreateWorkerPoolRequest) (*longrunningpb.Operation, error)
	// Returns details of a `WorkerPool`.
	GetWorkerPool(context.Context, *GetWorkerPoolRequest) (*WorkerPool, error)
	// Deletes a `WorkerPool`.
	DeleteWorkerPool(context.Context, *DeleteWorkerPoolRequest) (*longrunningpb.Operation, error)
	// Updates a `WorkerPool`.
	UpdateWorkerPool(context.Context, *UpdateWorkerPoolRequest) (*longrunningpb.Operation, error)
	// Lists `WorkerPool`s.
	ListWorkerPools(context.Context, *ListWorkerPoolsRequest) (*ListWorkerPoolsResponse, error)
	// Returns the `DefaultServiceAccount` used by the project.
	GetDefaultServiceAccount(context.Context, *GetDefaultServiceAccountRequest) (*DefaultServiceAccount, error)
}

